// On récupère le texte de Claude
let t = $json.text || '';

// On nettoie les balises ```json et ```
t = t.replace(/^```json\s*/i, '').replace(/\s*```$/i, '').trim();

try {
  const d = JSON.parse(t);
  return d.item || [];
} catch (e) {
  throw new Error('Erreur JSON: ' + e.message);
}
